+        let p = percentiles.unwrap();
+        assert!(p.count >= 1);
+        assert!(p.mean_ms >= 0.0);
+        assert!(p.p50_ms >= 0.0);
+        assert!(p.p95_ms >= p.p50_ms);
+        assert!(p.p99_ms >= p.p95_ms);
+    }
